/* ===================================
 顶栏 — 白色渐变到底部虚化透明
==================================== */
.chat-detail-screen {
  background: url('https://i.postimg.cc/MH0kJymK/BCA6D2E7-39EF-40B4-ADF9-CBFC49076177.png') no-repeat center/cover fixed !important;
  position: relative !important;
}

/* 背景图的白色矩形调节区域！ */
.chat-detail-screen::after {
  content: "" !important;
  position: absolute !important;
  top: 50% !important;
  left: 50% !important;
  transform: translate(-50%, -50%) !important;
  width: 95% !important;        /* 数越大左右越宽 */
  height: 80% !important;        /* 数越小上下越窄 */
  background: #ffffff !important;
  border-radius: 20px !important;
  pointer-events: none !important;
  z-index: 0 !important;
}

.chat-header-custom {
  --chat-header-height: 100px !important;
  position: relative !important;
  margin-top: 0px !important;    
  height: var(--chat-header-height) !important;  
  border-radius: 0px !important;
  background: transparent !important;  /* 改成透明 */
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* 玻璃层透明 */
.chat-header-custom .glass-header {
  background: transparent !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

.chat-header-custom,
.chat-header-custom .glass-header {
  border: none !important;
  outline: none !important;
  box-shadow: none !important;
}

/* ===== 去掉顶栏阴影 ===== */
.chat-header-custom,
.chat-header-custom .glass-header {
  box-shadow: none !important;
  border: none !important;
  outline: none !important;
}

/* ===== 头像显示 + 调节 ===== */
.chat-header-custom .header-avatar-container,
.chat-header-custom .chat-header-avatar {
  display: flex !important;           /* 显示头像 */
  position: absolute !important;
  left: 50px !important;              /* 👈 正数右 */
  top: 45% !important;                /* 👈 上下位置（百分比） */
  transform: translateY(-50%) !important; 
  width: 45px !important;            
  height: 45px !important;           
  border-radius: 50% !important;     
  overflow: hidden !important;
  border: 1.5px solid #FFFFFF !important;
  outline-offset: 0px !important;
  box-shadow: 1.5px 1.5px 2px #CCCCCC !important;
}

/* 顶栏第二头像（在原头像旁边） */
.chat-header-custom::before {
  content: "" !important;
  position: absolute !important;
  left: 90px !important;             /* 👈 在原头像右侧，调这个 */
  top: 45% !important;
  transform: translateY(-50%) !important;
  width: 43px !important;
  height: 43px !important;
  border-radius: 50% !important;
  background: url('https://i.postimg.cc/FHJpB9r3/38E98989-FBEB-4C4D-9F4B-76B71D3520EF.jpg') no-repeat center/cover !important;
  border: 1.5px solid #FFFFFF !important;
  box-shadow: 1.5px 1.5px 2px #CCCCCC !important;
  pointer-events: none !important;
  z-index: 10 !important;
}

/* ===== 昵称（备注偏移改这里‼️） ===== */
.chat-header-custom .chat-header-title {
  color: #3F3F3F !important;
  font-weight: 600 !important;
  font-size: 17px !important;
  position: absolute !important;
  left: 145px !important;                    /* 👈 正数右 */
  top: 40% !important;                      /* 👈正数下 */
  transform: translateY(-50%) !important;
  margin-left: 0 !important;
  margin-top: 0px !important;
  white-space: nowrap !important;
  text-align: left !important;
  width: auto !important;
  display: flex !important;
  align-items: center !important;
}

/* ===== 昵称下面的ID文案（改这里‼️） ===== */
.chat-header-custom .chat-header-title::after {
  content: "@babychii" !important;
  position: absolute !important;
  left: 0px !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
  margin-top: 16px !important;
  font-size: 12px !important;
  font-weight: 400 !important;
  color: #aaaaaa !important;
  white-space: nowrap !important;
  pointer-events: none !important;
  z-index: 20 !important;
}

/* ====================================
               返回按钮位置改这里
======================================*/
.chat-header-custom .header-btn-back {
  background: transparent !important;
  border-radius: 50% !important;
  width: 35px !important;
  height: 35px !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  -webkit-tap-highlight-color: transparent !important;
  margin-left: 0px !important;  
  margin-top: 0px !important;  
  position: relative !important;
}

/* 隐藏原有SVG图标 */
.chat-header-custom .header-btn-back svg {
  display: none !important;
}

/* 用伪元素画细线左箭头 */
.chat-header-custom .header-btn-back::before {
  content: "" !important;
  position: absolute !important;
  width: 13px !important;
  height: 13px !important;
  background: transparent !important;
  border-left: 2px solid #aaaaaa !important;
  border-bottom: 2px solid #aaaaaa !important;
  transform: rotate(45deg) !important;
  left: 10px !important;  /* 👈 正数往右，负数往左 */
  top: 6px !important;   /* 👈 正数往下，负数往上 */
}

/* ===== 右侧按钮（已隐藏） ===== */
.chat-header-custom .header-action-btn {
  background: transparent !important;
  border-radius: 50% !important;
  width: 34px !important;
  height: 34px !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  -webkit-tap-highlight-color: transparent !important;
  margin-right: 0px !important;
  margin-top: 0px !important;
}

/* ====================================
               设置按钮位置改这里
======================================*/
.header-action-btn:last-child svg {
  display: none !important;
}
.header-action-btn:last-child {
  background-image: url('https://i.postimg.cc/TPk1XKXL/32F35947-FDEB-4CF5-B3D6-07E1BB05C4A9.png') !important;  
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  background-color: transparent !important;
  width: 20px !important;
  height: 20px !important;
  margin-top: 0px !important;      /* 👈 正数往下，负数往上 */
  margin-right: 0px !important;    /* 👈 正数往左，负数往右 */
  opacity: 1 !important;
  pointer-events: auto !important;
}

/* 隐藏电话按钮但可点击 */
.chat-header-custom .header-btn-phone {
  opacity: 0 !important;
}

/* 隐藏视频按钮但可点击 */
.chat-header-custom .header-btn-video {
  opacity: 0 !important;
}

/* =========================================
   底栏➕输入框➕按钮部分 ‼️
 ========================================= */

/* 底栏容器 - 透明毛玻璃（透壁纸，遮气泡） */
.input-area-custom {
  background: transparent !important;
  backdrop-filter: blur(0.5px) !important;
