/* ====================================
               ai按钮和位置改这里‼️
======================================*/
.input-btn-ai {
  position: absolute !important;
  bottom: 0px !important;          /* 👈 上下位置：越大越往上 */
  right: -3px !important;         /* 👈 左右位置：负数越靠右，正数越靠左 */
  background: transparent !important;
  border-radius: 0 !important;
  padding: 0 !important;
  position: absolute !important;
}

/* 用url贴图替换ai图标 - 绝对居中放大 */
.input-btn-ai::before {
  content: "" !important;
  position: absolute !important;
  width: 20px !important;
  height: 20px !important;
  background-image: url("https://i.postimg.cc/TPk1XKXL/32F35947-FDEB-4CF5-B3D6-07E1BB05C4A9.png") !important;
