/* 1. 将顶栏变成悬浮的胶囊 */
.chat-detail-screen .glass-header {
  border-radius: 50px !important; 
  margin: 10px 16px 0px 16px !important; 
  padding-top: 2px !important; 
  padding-bottom: 0px !important;
  border-bottom: none !important;
