}

/* =======================================
   🌟【新增】胶囊呼吸灯动画 - 同色系涟漪慢一点 🌟
   ======================================= */
@keyframes breathingBlackGlow {
  0% {
    opacity: 0.2;
    box-shadow: 0 0 0px rgba(100, 100, 100, 0);
    transform: scale(1);
  }
  50% {
    opacity: 1;
    /* 同色系涟漪光圈：外层深灰，内层柔和银光 */
    box-shadow: 0 0 15px rgba(100, 100, 100, 0.4), inset 0 0 8px rgba(200, 200, 200, 0.5);
    transform: scale(1.01);
  }
  100% {
    opacity: 0.2;
    box-shadow: 0 0 0px rgba(100, 100, 100, 0);
    transform: scale(1);
  }
}

/* 呼吸灯实体：包裹在顶栏外侧的光圈 */
.chat-detail-screen .glass-header::before {
  content: "";
  position: absolute;
  top: -1.5px; 
  bottom: -1.5px; 
  left: -1.5px; 
  right: -1.5px; 
  border-radius: 50px;
  border: 1.5px solid rgba(180, 180, 180, 0.8); 
