  transform: scale(0.85) !important;
  transition: transform 0.1s cubic-bezier(0.4, 0, 0.2, 1) !important;
}

/* =======================================
   气泡与核心样式
   ======================================= */
:root {
  /* 1. 对方气泡（铂金银灰） */
  --bubble-them-bg: #E5E5E5;
  --bubble-them-bg-gradient: linear-gradient(180deg, #DBDBDB 0%, #F0F0F0 100%);
  --bubble-them-color: #1F1F1F; 
  --bubble-them-border: none; 
  --bubble-them-font-size: 14px; 
  --bubble-them-line-height: 1.4;
  --bubble-them-shadow: inset 0 1.5px 1px rgba(255, 255, 255, 0.9), inset 0 -3px 4px rgba(255, 255, 255, 0.6), 0 1.5px 2px rgba(0, 0, 0, 0.15);
  --bubble-them-radius: 8px;
  --bubble-them-radius-first: 8px;
  --bubble-them-radius-mid: 8px;
  --bubble-them-radius-last: 8px;
  --bubble-them-padding: 7px 12px;

  /* 2. 我方气泡（黑曜石） */
  --bubble-me-bg: #1F1F1F;
  --bubble-me-bg-gradient: linear-gradient(180deg, #2A2A2A 0%, #141414 100%);
  --bubble-me-color: #FFFFFF;
  --bubble-me-border: none; 
  --bubble-me-font-size: 14px;
  --bubble-me-line-height: 1.4;
  --bubble-me-shadow: inset 0 1.5px 1px rgba(255, 255, 255, 0.25), inset 0 -3px 4px rgba(255, 255, 255, 0.1), 0 1.5px 2px rgba(0, 0, 0, 0.6);
  --bubble-me-radius: 8px;
  --bubble-me-radius-first: 8px;
  --bubble-me-radius-mid: 8px;
  --bubble-me-radius-last: 8px;
  --bubble-me-padding: 7px 12px;
  --bubble-me-text-shadow: 0 1px 1px rgba(0, 0, 0, 0.5);

  --avatar-size: 36px; 
  --plain-avatar-size: 36px;
  --plain-padding-left-me: 60px;  
  --plain-padding-right-me: 0px; 
}

/* 头像显隐控制 */
.msg-avatar-them-container { visibility: hidden !important; position: relative !important; overflow: visible !important; }
.msg-avatar-them-container.is-first, .msg-avatar-them-container.is-single { visibility: visible !important; }

.msg-avatar-me-container { 
  visibility: hidden !important; 
  display: block !important; 
  margin-left: 8px !important; 
  margin-right: 0px !important; 
  position: relative !important; 
  overflow: visible !important; 
}
.msg-avatar-me-container.is-first, .msg-avatar-me-container.is-single { visibility: visible !important; }

.msg-bubble-wrapper.msg-me { justify-content: flex-end !important; align-items: flex-start !important; }
.msg-bubble-wrapper.msg-me .msg-content-stack { align-items: flex-end !important; }

/* 对方头像（银灰系） */
.msg-avatar-them-inner {
  border-radius: 8px !important; 
  border: 2px solid #F0F0F0 !important; 
  box-shadow: 0 0 0 1px #DBDBDB, 0 3px 5px rgba(0, 0, 0, 0.1) !important;
  will-change: transform, box-shadow; 
  animation: avatarBreathing 4s infinite ease-in-out;
}

/* 我方头像（黑石系） */
.msg-avatar-me-inner {
  border-radius: 8px !important;
  border: 2px solid #2A2A2A !important; 
  box-shadow: 0 0 0 1px #0A0A0A, 0 3px 5px rgba(0, 0, 0, 0.5) !important;
  will-change: transform, box-shadow;
  animation: myAvatarBreathing 4s infinite ease-in-out;
}

/* 头像发光小字 */
.msg-avatar-them-container::after {
  content: '@XLSS'; 
  position: absolute;
  bottom: -16px; left: 50%; transform: translateX(-50%);
  font-size: 10px; font-weight: 600; letter-spacing: 0.5px;
  color: #1F1F1F; white-space: nowrap;
  text-shadow: 0 0 5px rgba(180, 180, 180, 0.8), 0 0 10px rgba(180, 180, 180, 0.6);
  pointer-events: none;
}

.msg-avatar-me-container::after {
  content: '@SVG';
  position: absolute;
  bottom: -16px; left: 50%; transform: translateX(-50%);
  font-size: 10px; font-weight: 600; letter-spacing: 0.5px;
  color: #1F1F1F; white-space: nowrap;
  text-shadow: 0 0 5px rgba(180, 180, 180, 0.8), 0 0 10px rgba(180, 180, 180, 0.6);
  pointer-events: none;
}

/* 头像呼吸动画 */
@keyframes avatarBreathing {
  0% { transform: scale(1); box-shadow: 0 0 0 1px #DBDBDB, 0 3px 5px rgba(0, 0, 0, 0.1); }
  50% { transform: scale(1.08); box-shadow: 0 0 0 1px #DBDBDB, 0 6px 12px rgba(0, 0, 0, 0.2); }
  100% { transform: scale(1); box-shadow: 0 0 0 1px #DBDBDB, 0 3px 5px rgba(0, 0, 0, 0.1); }
}

@keyframes myAvatarBreathing {
  0% { transform: scale(1); box-shadow: 0 0 0 1px #0A0A0A, 0 3px 5px rgba(0, 0, 0, 0.5); }
  50% { transform: scale(1.08); box-shadow: 0 0 0 1px #0A0A0A, 0 6px 12px rgba(0, 0, 0, 0.7); }
  100% { transform: scale(1); box-shadow: 0 0 0 1px #0A0A0A, 0 3px 5px rgba(0, 0, 0, 0.5); }
}

/* 气泡滑入动画 */
@keyframes slideInFromLeft {
  0% { opacity: 0; transform: translateX(-20px) scale(0.9); }
  100% { opacity: 1; transform: translateX(0) scale(1); }
}
@keyframes slideInFromRight {
  0% { opacity: 0; transform: translateX(20px) scale(0.9); }
  100% { opacity: 1; transform: translateX(0) scale(1); }
}
.msg-bubble-wrapper.msg-them { animation: slideInFromLeft 0.3s ease-out forwards; }
.msg-bubble-wrapper.msg-me { animation: slideInFromRight 0.3s ease-out forwards; }

/* =======================================
   组件、菜单与卡片色系统一
   ======================================= */
:root {
  /* 1. 菜单栏 */
  --more-options-bg: rgba(245, 245, 245, 0.95); 
  --more-options-border: 1px solid #CCCCCC; 
  --more-options-color: #1F1F1F; 
  --more-options-divider: rgba(0, 0, 0, 0.1); 

  /* 2. 输入框上方文字 */
  --reply-bar-accent: #1F1F1F; 
  --reply-bar-text-color: rgba(31, 31, 31, 0.8); 

  /* 3. 多选模式 */
  --selection-checkbox-border: #CCCCCC; 
  --selection-checkbox-checked-bg: #1F1F1F; 
  --selection-checkbox-icon-color: #FFFFFF; 

  /* 4. 引用与回复区块 */
  --quote-border-color: rgba(31, 31, 31, 0.45); 
  --quote-text-color: #1F1F1F; 

  --reply-block-bg: rgba(31, 31, 31, 0.06); 
  --reply-block-name-color: #1F1F1F; 
  --reply-block-text-color: rgba(31, 31, 31, 0.8); 

  --reply-me-bg: rgba(245, 245, 245, 0.15); 
  --reply-me-name-color: #F5F5F5; 
  --reply-me-text-color: rgba(255, 255, 255, 0.85); 
  --reply-me-border-left: 3px solid rgba(245, 245, 245, 0.5); 

  --reply-them-bg: rgba(31, 31, 31, 0.08); 
  --reply-them-name-color: #1F1F1F; 
  --reply-them-text-color: rgba(31, 31, 31, 0.85); 
  --reply-them-border-left: 3px solid #1F1F1F; 

  /* 5. 转账卡片 */
  --transfer-card-bg: #F5F5F5;
  --transfer-card-border: 1px solid #CCCCCC;
  --transfer-icon-bg: #1F1F1F;
  --transfer-amount-color: #1F1F1F;

  --transfer-me-card-bg: #1F1F1F;
  --transfer-me-card-border: 1px solid #404040;
  --transfer-me-icon-bg: #F5F5F5; 
  --transfer-me-amount-color: #FFFFFF; 
  --transfer-me-label-color: rgba(255, 255, 255, 0.85);
  --transfer-me-subtitle-color: rgba(255, 255, 255, 0.6);
  --transfer-me-status-color: rgba(255, 255, 255, 0.8);
  --transfer-me-divider-color: rgba(255, 255, 255, 0.15);

  --transfer-them-card-bg: #E5E5E5;
  --transfer-them-card-border: 1px solid #DBDBDB;
  --transfer-them-icon-bg: #1F1F1F; 
  --transfer-them-amount-color: #1F1F1F; 
  --transfer-them-label-color: rgba(31, 31, 31, 0.85);
  --transfer-them-subtitle-color: rgba(31, 31, 31, 0.6);
  --transfer-them-status-color: rgba(31, 31, 31, 0.8);
  --transfer-them-divider-color: rgba(31, 31, 31, 0.15);

  /* 6. 转发消息与系统字 */
  --forward-msg-bg: rgba(31, 31, 31, 0.08); 
  --forward-msg-color: #1F1F1F;
  --system-msg-bg: rgba(31, 31, 31, 0.06); 
  --system-msg-color: #1F1F1F;

  /* 7. 长按弹窗与表情栏 */
  --reaction-bar-bg: rgba(245, 245, 245, 0.95); 
  --reaction-bar-shadow: 0 4px 15px rgba(0, 0, 0, 0.15); 
  --context-menu-bg: rgba(245, 245, 245, 0.95); 
  --context-menu-shadow: 0 8px 24px rgba(0, 0, 0, 0.15); 
  --context-menu-item-hover: rgba(31, 31, 31, 0.05); 
  --emoji-panel-bg: #F5F5F5;
  --emoji-panel-shadow: 0 -1px 0 rgba(0, 0, 0, 0.1);

  /* 8. 旁白与时间戳 */
  --narration-color: #1F1F1F; 
  --narration-bg: rgba(245, 245, 245, 0.85); 
  --narration-border: 1px solid rgba(0, 0, 0, 0.1); 
  --narration-shadow: 0 4px 15px rgba(0, 0, 0, 0.1); 
  --narration-padding: 6px 14px; 
  --narration-radius: 16px; 

  --date-divider-color: #1F1F1F;
  --date-divider-bg: rgba(245, 245, 245, 0.85);
  --date-divider-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}

.ig-context-menu, .ig-menu-item { color: #1F1F1F !important; }
.ig-menu-item svg { color: #1F1F1F !important; stroke: #1F1F1F !important; fill: currentColor !important; }
.ig-context-menu { border: 1px solid rgba(0, 0, 0, 0.1) !important; }

/* 普通时间戳 */
.timestamp-custom {
  background: rgba(245, 245, 245, 0.85) !important; 
  color: #1F1F1F !important; 
  padding: 4px 12px !important; 
  border-radius: 20px !important; 
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1) !important; 
  width: max-content !important; 
  display: block !important;
  margin: 12px auto !important; 
  font-size: 11px !important;
  font-weight: bold !important;
}

/* 旁白轻柔入场 */
@keyframes narrationFadeInUp {
  0% { opacity: 0; transform: translateY(12px) scale(0.95); }
  100% { opacity: 1; transform: translateY(0) scale(1); }
}
.msg-narration-custom {
  animation: narrationFadeInUp 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards !important;
  display: inline-block !important;
  width: max-content !important;
  max-width: 85% !important; 
  margin-left: auto !important;
  margin-right: auto !important;
}

/* 弹窗果冻入场 */
@keyframes jellyPop {
  0% { transform: scale(0.8) translateY(15px); opacity: 0; }
  50% { transform: scale(1.03) translateY(-2px); opacity: 1; }
  100% { transform: scale(1) translateY(0); opacity: 1; }
}
.ig-context-menu, .reaction-bar, .more-options-popup {
  animation: jellyPop 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) forwards !important;
  transform-origin: bottom center !important; 
}

