  --bubble-me-shadow: inset 0 1.5px 1px rgba(255, 255, 255, 0.25), inset 0 -3px 4px rgba(255, 255, 255, 0.1), 0 1.5px 2px rgba(0, 0, 0, 0.6);
  --bubble-me-radius: 8px;
  --bubble-me-radius-first: 8px;
  --bubble-me-radius-mid: 8px;
  --bubble-me-radius-last: 8px;
