  will-change: transform, box-shadow; 
  animation: avatarBreathing 4s infinite ease-in-out;
}

/* 我方头像（黑石系） */
.msg-avatar-me-inner {
  border-radius: 8px !important;
  border: 2px solid #2A2A2A !important; 
  box-shadow: 0 0 0 1px #0A0A0A, 0 3px 5px rgba(0, 0, 0, 0.5) !important;
