/* ==========================================
   气泡
   ========================================== */

:root {
  --chat-messages-gap: 12px;
}

:root {
  --bubble-me-bg: #ffffff;
  --bubble-me-color: #262626;
  --bubble-me-border: 0.8px solid #c0c0c6;
  --bubble-me-padding: 6px 16px;
  --bubble-me-font-size: 16px;
  --bubble-me-radius: 20px;
  --bubble-me-radius-first: 20px 20px 4px 20px;
  --bubble-me-radius-mid: 20px 4px 4px 20px;
  --bubble-me-radius-last: 20px 4px 20px 20px;
}

:root {
  --bubble-them-bg: #e8e8ec;
  --bubble-them-color: #262626;
  --bubble-them-border: none;
  --bubble-them-padding: 6px 16px;
  --bubble-them-font-size: 16px;
  --bubble-them-radius: 20px;
  --bubble-them-radius-first: 20px 20px 20px 4px;
  --bubble-them-radius-mid: 4px 20px 20px 4px;
  --bubble-them-radius-last: 4px 20px 20px 20px;
}

/* 对方头像：只在第一条显示 */
.msg-avatar-them-container { display: none !important; }

.msg-avatar-them-container.is-first,
.msg-avatar-them-container.is-single {
  display: flex !important;
  visibility: visible !important;
  opacity: 1 !important;
}

/* 我方头像隐藏 */
.msg-avatar-me-container { display: none !important; }

/* 头像强制圆形 */
.msg-avatar-them-inner,
.msg-avatar-them-container img {
  border-radius: 50% !important;
  overflow: hidden !important;
}

/* 隐藏隐形触控区 */
.msg-avatar-them-ghost { display: none !important; }

/* 对方头像用 absolute 提到气泡上方 */
.msg-them .msg-avatar-them-container.is-first,
.msg-them .msg-avatar-them-container.is-single {
  position: relative !important;
}

.msg-them .msg-avatar-them-container.is-first .msg-avatar-them-inner,
.msg-them .msg-avatar-them-container.is-single .msg-avatar-them-inner {
  position: absolute !important;
  top: -48px !important;
  left: 0 !important;
  overflow: visible !important;
}

/* 第一条消息顶部留空间 */
.msg-them.msg-bubble-wrapper.is-first,
.msg-them.msg-bubble-wrapper.is-single {
  margin-top: 54px !important;
  margin-left: 0 !important;
  padding-left: 0 !important;
}

.msg-them .msg-avatar-them-container.is-first,
.msg-them .msg-avatar-them-container.is-single {
  width: 0 !important;
  height: 0 !important;
  margin: 0 !important;
  padding: 0 !important;
}

/* 头像右侧：ID */
.msg-them .msg-avatar-them-container.is-first::after,
.msg-them .msg-avatar-them-container.is-single::after {
  content: "@role_id";
  /* ↑ 改这里的文字🩶 */
  position: absolute;
  top: -48px;
  left: 48px;
  white-space: nowrap;
  font-size: 11px;
  font-weight: 400;
  color: #6b7280;
  letter-spacing: 0.3px;
  line-height: 1.5;
  padding-right: 20px;
}

/* 小图 */
.msg-them .msg-avatar-them-container.is-first::before,
.msg-them .msg-avatar-them-container.is-single::before {
  content: "";
  position: absolute;
  top: -48px;
  left: calc(48px + 48px);
  width: 16px;
  height: 16px;
  background-image: url("https://i.postimg.cc/Hxx1QMBG/IMG-4225.png");
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  border-radius: 4px;
  pointer-events: none;
  z-index: 5;
}

/* 头像下方文案 */
.msg-them .msg-avatar-them-container.is-first .msg-avatar-them-inner::after,
.msg-them .msg-avatar-them-container.is-single .msg-avatar-them-inner::after {
  content: "🤍";
  /* ↑ 改这里的文字🩶 */
  position: absolute;
  top: 20px;
  left: calc(100% + 8px);
  font-size: 11px;
  font-weight: 400;
  color: #6b7280;
  letter-spacing: 0.3px;
  line-height: 1.5;
  white-space: nowrap;
  pointer-events: none;
}

/* 气泡间距 */
.msg-bubble-wrapper {
    margin-bottom: 8px !important;
}

.msg-bubble-wrapper.is-first,
.msg-bubble-wrapper.is-mid {
    margin-bottom: 8px !important;
}

.msg-bubble-wrapper.is-last,
.msg-bubble-wrapper.is-single {
    margin-bottom: 16px !important;
}


