/* ==========================================
   气泡
   ========================================== */

:root {
  --chat-messages-gap: 12px;
}

:root {
  --bubble-me-bg: #ffffff;
  --bubble-me-color: #262626;
  --bubble-me-border: 0.8px solid #c0c0c6;
  --bubble-me-padding: 6px 16px;
  --bubble-me-font-size: 16px;
  --bubble-me-radius: 20px;
  --bubble-me-radius-first: 20px 20px 4px 20px;
  --bubble-me-radius-mid: 20px 4px 4px 20px;
  --bubble-me-radius-last: 20px 4px 20px 20px;
}

:root {
  --bubble-them-bg: #e8e8ec;
  --bubble-them-color: #262626;
  --bubble-them-border: none;
  --bubble-them-padding: 6px 16px;
  --bubble-them-font-size: 16px;
  --bubble-them-radius: 20px;
  --bubble-them-radius-first: 20px 20px 20px 4px;
  --bubble-them-radius-mid: 4px 20px 20px 4px;
  --bubble-them-radius-last: 4px 20px 20px 20px;
}

/* 对方头像：只在第一条显示 */
.msg-avatar-them-container { display: none !important; }

.msg-avatar-them-container.is-first,
.msg-avatar-them-container.is-single {
  display: flex !important;
  visibility: visible !important;
  opacity: 1 !important;
}

/* 我方头像隐藏 */
.msg-avatar-me-container { display: none !important; }

/* 头像强制圆形 */
.msg-avatar-them-inner,
.msg-avatar-them-container img {
  border-radius: 50% !important;
  overflow: hidden !important;
}

/* 隐藏隐形触控区 */
.msg-avatar-them-ghost { display: none !important; }

/* 对方头像用 absolute 提到气泡上方 */
.msg-them .msg-avatar-them-container.is-first,
.msg-them .msg-avatar-them-container.is-single {
  position: relative !important;
}

.msg-them .msg-avatar-them-container.is-first .msg-avatar-them-inner,
.msg-them .msg-avatar-them-container.is-single .msg-avatar-them-inner {
  position: absolute !important;
  top: -48px !important;
  left: 0 !important;
  overflow: visible !important;
}

/* 第一条消息顶部留空间 */
.msg-them.msg-bubble-wrapper.is-first,
.msg-them.msg-bubble-wrapper.is-single {
  margin-top: 54px !important;
  margin-left: 0 !important;
  padding-left: 0 !important;
}

.msg-them .msg-avatar-them-container.is-first,
.msg-them .msg-avatar-them-container.is-single {
  width: 0 !important;
  height: 0 !important;
  margin: 0 !important;
  padding: 0 !important;
}

/* 头像右侧：ID */
.msg-them .msg-avatar-them-container.is-first::after,
.msg-them .msg-avatar-them-container.is-single::after {
  content: "@role_id";
  /* ↑ 改这里的文字🩶 */
  position: absolute;
  top: -48px;
  left: 48px;
  white-space: nowrap;
  font-size: 11px;
  font-weight: 400;
  color: #6b7280;
  letter-spacing: 0.3px;
  line-height: 1.5;
  padding-right: 20px;
}

/* 小图 */
.msg-them .msg-avatar-them-container.is-first::before,
.msg-them .msg-avatar-them-container.is-single::before {
  content: "";
  position: absolute;
  top: -48px;
  left: calc(48px + 48px);
  width: 16px;
  height: 16px;
  background-image: url("https://i.postimg.cc/Hxx1QMBG/IMG-4225.png");
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  border-radius: 4px;
  pointer-events: none;
  z-index: 5;
}

/* 头像下方文案 */
.msg-them .msg-avatar-them-container.is-first .msg-avatar-them-inner::after,
.msg-them .msg-avatar-them-container.is-single .msg-avatar-them-inner::after {
  content: "🤍";
  /* ↑ 改这里的文字🩶 */
  position: absolute;
  top: 20px;
  left: calc(100% + 8px);
  font-size: 11px;
  font-weight: 400;
  color: #6b7280;
  letter-spacing: 0.3px;
  line-height: 1.5;
  white-space: nowrap;
  pointer-events: none;
}

/* 气泡间距 */
.msg-bubble-wrapper {
    margin-bottom: 8px !important;
}

.msg-bubble-wrapper.is-first,
.msg-bubble-wrapper.is-mid {
    margin-bottom: 8px !important;
}

.msg-bubble-wrapper.is-last,
.msg-bubble-wrapper.is-single {
    margin-bottom: 16px !important;
}


/* =============================================
   底栏
   ============================================= */
.input-area-custom {
    position: absolute !important;
    bottom: 0 !important;
    left: 0 !important;
    right: 0 !important;
    z-index: 60 !important;
    background: transparent !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    border-top: none !important;
    padding: 8px 12px 8px 12px !important;
    padding-bottom: max(8px, var(--nuo-safe-bottom)) !important;
    overflow: visible !important;
    transform: none !important;
}

.input-area-custom::before,
.input-area-custom::after {
    display: none !important;
    content: none !important;
}

.input-row-wrapper {
    display: flex !important;
    flex-direction: row !important;
    align-items: flex-end !important;
    gap: 10px !important;
    position: relative !important;
    z-index: 10 !important;
    margin-bottom: 0 !important;
}

/* 加号按钮 */
.input-btn-plus {
    position: relative !important;
    background: rgba(255, 255, 255, 0.5) !important;
    backdrop-filter: blur(20px) saturate(100%) !important;
    -webkit-backdrop-filter: blur(20px) saturate(100%) !important;
    border: none !important;
    border-radius: 50% !important;
    width: 36px !important;
    height: 36px !important;
    bottom: -6px !important;
    /* ↑ 加号按钮向下偏移量 */
    min-width: 34px !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    margin: 0 !important;
    flex-shrink: 0 !important;
    cursor: pointer !important;
    overflow: hidden !important;
    box-shadow:
        inset 1px 1px 0 0 rgba(255, 255, 255, 0.6),
        inset -1px -1px 0 0 rgba(255, 255, 255, 0.3),
        0 4px 12px rgba(0, 0, 0, 0.08),
        0 2px 4px rgba(0, 0, 0, 0.04) !important;
    transform: translateZ(0) !important;
}
.input-btn-plus > * {
    position: relative !important;
    z-index: 1 !important;
}
.input-btn-plus:active {
    background: rgba(255, 255, 255, 0.65) !important;
    transform: scale(0.92) translateZ(0) !important;
    box-shadow:
        inset 1px 1px 0 0 rgba(255, 255, 255, 0.4),
        0 2px 6px rgba(0, 0, 0, 0.06) !important;
}
.input-btn-plus svg {
    width: 24px !important;
    height: 24px !important;
    color: #3d3a40 !important;
    stroke: #3d3a40 !important;
    stroke-width: 1.8 !important;
}

/* 输入胶囊 */
.input-action-bar-custom {
    flex: 1 !important;
    margin-right: 5px !important;
    transform: translateY(8px) translateZ(0) !important;
    /* ↑ 输入胶囊向下偏移量 */
    background: rgba(255, 255, 255, 0.5) !important;
    backdrop-filter: blur(20px) saturate(100%) !important;
    -webkit-backdrop-filter: blur(20px) saturate(100%) !important;
    border: 0.5px solid rgba(255, 255, 255, 0.3) !important;
    border-radius: 28px !important;
    padding: 0px 12px 0px 8px !important;
    min-height: 38px !important;
    height: 38px !important;
    max-height: 38px !important;
    display: flex !important;
    align-items: center !important;
    gap: 8px !important;
    overflow: hidden !important;
    box-shadow:
        inset 1px 1px 0 0 rgba(255, 255, 255, 0.6),
        inset -1px -1px 0 0 rgba(255, 255, 255, 0.3),
        0 4px 12px rgba(0, 0, 0, 0.08),
        0 2px 4px rgba(0, 0, 0, 0.04) !important;
}
.input-action-bar-custom > * {
    position: relative !important;
    z-index: 1 !important;
}

.input-box-custom {
    flex: 1 !important;
    background: transparent !important;
    border: none !important;
    color: #000000 !important;
    font-size: 16px !important;
    font-weight: 400 !important;
    line-height: 38px !important;
    padding: 0 !important;
    margin: 0 !important;
    resize: none !important;
    outline: none !important;
    -webkit-text-fill-color: #000000 !important;
    caret-color: #000000 !important;
    overflow: hidden !important;
    white-space: nowrap !important;
    text-overflow: ellipsis !important;
    height: 38px !important;
}
.input-box-custom::placeholder {
    color: transparent !important;
    opacity: 0 !important;
}

/* 自定义占位提示词 */
.input-action-bar-custom::before {
    content: "iMessage" !important;
    /* ↑ 改这里的提示文字🩶 */
    position: absolute !important;
    left: 14px !important;
    top: 50% !important;
    transform: translateY(-50%) !important;
    color: rgba(0, 0, 0, 0.25) !important;
    font-size: 14px !important;
    line-height: 1 !important;
    opacity: 1 !important;
    pointer-events: none !important;
    z-index: 10 !important;
}
.input-action-bar-custom:has(.input-box-custom:focus)::before,
.input-action-bar-custom:has(.input-box-custom:not(:empty))::before {
    display: none !important;
}

/* 右侧按钮组 */
.input-action-bar-custom > div:last-child {
    display: flex !important;
    flex-direction: row !important;
    align-items: center !important;
    gap: 6px !important;
    /* ↑ 右侧按钮之间的间距 */
    flex-shrink: 0 !important;
    margin-right: -10px !important;
    /* ↑ 右侧按钮组整体向右偏移 */
}

/* 表情按钮 (order 1) */
.input-btn-sticker {
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    background: transparent !important;
    border: none !important;
    padding: 8px !important;
    margin: 0 !important;
    cursor: pointer !important;
    opacity: 0 !important;
    pointer-events: auto !important;
    width: 32px !important;
    height: 32px !important;
    order: 1 !important;
}
.input-btn-sticker:active {
    opacity: 0 !important;
}
.input-btn-sticker svg {
    opacity: 0 !important;
    width: 0 !important;
    height: 0 !important;
    display: none !important;
}

/* 语音按钮 (order 2) */
.input-btn-mic {
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    background: transparent !important;
    border: none !important;
    padding: 0 !important;
    margin: 0 !important;
    cursor: pointer !important;
    opacity: 0 !important;
    pointer-events: auto !important;
    transition: opacity 0.2s ease !important;
    order: 2 !important;
    width: 32px !important;
    height: 32px !important;
    position: relative !important;
}
.input-btn-mic:active {
    opacity: 0 !important;
    transform: none !important;
    background: transparent !important;
}
.input-btn-mic svg {
    display: none !important;
}
.input-btn-mic::before {
    content: "" !important;
    display: block !important;
    width: 22px !important;
    height: 22px !important;
    background-image: url("https://i.postimg.cc/Vs2jGpmV/IMG_2308.png") !important;
    /* ↑ 语音按钮图标🩶 */
    background-size: contain !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
}

/* AI 按钮 (order 3) */
.input-btn-ai {
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    background: transparent !important;
    border: none !important;
    padding: 0 !important;
    margin: 0 !important;
    cursor: pointer !important;
    opacity: 0.7 !important;
    pointer-events: auto !important;
    transition: opacity 0.2s ease !important;
    width: 32px !important;
    height: 32px !important;
    order: 3 !important;
    position: relative !important;
}
.input-btn-ai:active {
    opacity: 1 !important;
    transform: none !important;
    background: transparent !important;
}
.input-btn-ai svg {
    display: none !important;
}
.input-btn-ai::before {
    content: "" !important;
    display: block !important;
    width: 28px !important;
    height: 28px !important;
    background-image: url("https://i.postimg.cc/MTrPkctL/IMG-3833.png") !important;
    /* ↑ AI按钮图标🩶 */
    background-size: contain !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
}

/* 发送按钮 (order 4) */
:root {
    --send-btn-url: url("https://i.postimg.cc/MTrPkctL/IMG-3833.png");
    /* ↑ 发送按钮图标🩶 */
    --send-btn-width: 40px;
    --send-btn-height: 40px;
}

.send-btn-custom {
    background: transparent !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    border: none !important;
    border-radius: 0 !important;
    width: 40px !important;
    height: 40px !important;
    min-width: 36px !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    margin: 0 !important;
    cursor: pointer !important;
    box-shadow: none !important;
    transition: opacity 0.2s ease !important;
    order: 4 !important;
    position: relative !important;
}
.send-btn-custom:active {
    transform: none !important;
    opacity: 0.8 !important;
    background: transparent !important;
}
.send-btn-custom svg {
    display: none !important;
}
.send-btn-custom::before {
    content: "" !important;
    display: block !important;
    width: var(--send-btn-width) !important;
    height: var(--send-btn-height) !important;
    background-image: var(--send-btn-url) !important;
    background-size: contain !important;
    background-repeat: no-repeat !important;
