/* 更多菜单 */
.input-area-custom .more-options-popup {
    background: #ffffff !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    border-radius: 20px !important;
    border: 1px solid rgba(0, 0, 0, 0.1) !important;
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.12) !important;
    overflow: hidden !important;
    padding: 8px 0 !important;
}
.input-area-custom .more-options-item-row {
    padding: 12px 16px !important;
    cursor: pointer !important;
}
.input-area-custom .more-options-item-row:active {
    background: rgba(0, 0, 0, 0.04) !important;
}
.input-area-custom .more-options-item-row span {
    color: #000000 !important;
    font-size: 15px !important;
    font-weight: 500 !important;
}


/* =============================================
   顶栏
   ============================================= */
.chat-header-custom {
  position: relative !important;
  background: transparent !important;
  border-bottom: none !important;
  box-shadow: none !important;
}

/* 第一层模糊 */
.chat-detail-screen .chat-header-custom::before {
  content: "" !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  z-index: -1 !important;
  pointer-events: none !important;
  backdrop-filter: blur(8px) saturate(130%) !important;
  -webkit-backdrop-filter: blur(8px) saturate(130%) !important;
  background: transparent !important;
  mask-image: linear-gradient(to bottom,
      black 0%,
      black 50%,
      rgba(0,0,0,0.6) 75%,
      transparent 100%) !important;
  -webkit-mask-image: linear-gradient(to bottom,
      black 0%,
      black 50%,
      rgba(0,0,0,0.6) 75%,
      transparent 100%) !important;
}

/* 第二层模糊 */
.chat-detail-screen .chat-header-custom::after {
  content: "" !important;
  position: absolute !important;
  top: -30px !important;
  left: 0 !important;
  right: 0 !important;
  bottom: -20px !important;
  pointer-events: none !important;
  z-index: -2 !important;
  background: transparent !important;
  backdrop-filter: blur(14px) saturate(140%) !important;
  -webkit-backdrop-filter: blur(14px) saturate(140%) !important;
  mask-image: linear-gradient(to bottom,
