.glass-header {
  background: transparent !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  border-bottom: none !important;
}

/* 消息列表 padding */
.chat-message-list-custom {
  padding-top: calc(max(var(--nuo-safe-top), 12px) + 78px) !important;
  padding-bottom: calc(0px + var(--nuo-safe-bottom)) !important;
}

/* =============================================
   头像+备注的玻璃椭圆大球
   transform: translateX() 强制平移
   正数右移，负数左移
   ============================================= */
.header-profile-section {
  position: relative !important;
  background: rgba(255, 255, 255, 0.35) !important;
  backdrop-filter: blur(18px) saturate(180%) !important;
  -webkit-backdrop-filter: blur(18px) saturate(180%) !important;
  border-radius: 100px !important;
  border: 1px solid rgba(255, 255, 255, 0.3) !important;
  box-shadow:
    inset 1px 1px 0 0 rgba(255, 255, 255, 0.6),
    inset -1px -1px 0 0 rgba(255, 255, 255, 0.3),
    0 4px 12px rgba(0, 0, 0, 0.08),
    0 2px 4px rgba(0, 0, 0, 0.04) !important;
  padding: 6px 42px 5px 6px !important;
  display: flex !important;
  align-items: center !important;
  gap: 8px !important;
  /* ↓ 改这里左右移动整个椭圆 ↓ */
  transform: translateX(100px) !important;
}

/* 备注文字区域 */
.chat-header-title {
  position: relative !important;
  max-width: 120px !important;
  overflow: hidden !important;
  white-space: nowrap !important;
  text-overflow: ellipsis !important;
}

/* 名字下方 @id */
.chat-header-title::after {
  content: "@role_id";
  /* ↑ 改这里的ID文字🩶 */
  display: block;
  font-size: 11px;
  font-weight: 400;
  color: #6b7280;
  letter-spacing: 0.3px;
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 120px;
  pointer-events: none;
}

/* 小图 — 在椭圆右侧 */
.header-profile-section::after {
  content: "";
  position: absolute;
  right: 20px;
  /* ↑ 小图距离椭圆右边的距离 */
  top: 35%;
  /* ↑ 小图在椭圆中的上下位置 */
  transform: translateY(-50%);
  width: 23px;
  height: 23px;
  background-image: url('https://i.postimg.cc/Hxx1QMBG/IMG-4225.png');
  /* ↑ 小图链接🩶 */
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  border-radius: 6px;
  pointer-events: none;
  z-index: 3;
}

/* 头像 */
.chat-header-avatar {
  width: 35px !important;
  height: 35px !important;
}
.header-avatar-container {
  margin-left: 0 !important;
  width: 35px !important;
  height: 35px !important;
}

/* =============================================
   返回按钮
   ============================================= */
.header-btn-back {
  background: rgba(255, 255, 255, 0.35) !important;
  backdrop-filter: blur(18px) saturate(180%) !important;
  -webkit-backdrop-filter: blur(18px) saturate(180%) !important;
  border-radius: 100px !important;
  padding: 6px 14px !important;
  width: auto !important;
  height: auto !important;
  min-width: 44px;
  display: flex !important;
  align-items: center;
  gap: 6px;
  color: #1c1c1e !important;
  font-size: 14px;
  font-weight: 500;
  border: 1px solid rgba(255, 255, 255, 0.3) !important;
  box-shadow:
    inset 1px 1px 0 0 rgba(255, 255, 255, 0.6),
    inset -1px -1px 0 0 rgba(255, 255, 255, 0.3),
