  --forward-msg-color: #1F1F1F;
  --system-msg-bg: rgba(31, 31, 31, 0.06); 
  --system-msg-color: #1F1F1F;

  /* 7. 长按弹窗与表情栏 */
  --reaction-bar-bg: rgba(245, 245, 245, 0.95); 
