  margin-left: auto !important;
  margin-right: auto !important;
}

/* 弹窗果冻入场 */
@keyframes jellyPop {
  0% { transform: scale(0.8) translateY(15px); opacity: 0; }
  50% { transform: scale(1.03) translateY(-2px); opacity: 1; }
  100% { transform: scale(1) translateY(0); opacity: 1; }
}
