  height: calc(100% + 0px);
  border-radius: 50%;
  background-image: url("https://i.postimg.cc/Rh6KLtgN/IMG-4510.png");
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  pointer-events: none;
  z-index: 2;
}

/* 我方头像框 */
