  content: "";
  position: absolute;
  top: -20px;      /* 🩶 上下偏移 */
  left: 5px;     /* 🩶 左右偏移 */
  width: calc(100% + 0px);
  height: calc(100% + 0px);
  border-radius: 50%;
  background-image: url("https://i.postimg.cc/XqGdk5sj/IMG-4509.png");
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  pointer-events: none;
  z-index: 2;
}

