}

.msg-me:has(.voice-msg) .msg-content-stack {
  max-width: 130px !important;
  align-self: flex-end !important;
}

.msg-me.msg-bubble-wrapper:has(.voice-msg),
.msg-bubble-wrapper.msg-me:has(.voice-msg) {
  max-width: 130px !important;
  justify-content: flex-end !important;
  align-self: flex-end !important;
  margin-left: auto !important;
}

/* --- 对方 --- */
.bubble-them-custom:has(.voice-msg),
.bubble-deco-them:has(.voice-msg) {
  padding: 0 !important;
  width: auto !important;
  min-width: auto !important;
  max-width: 130px !important;
  overflow: visible !important;
  margin-right: auto !important;
}

.msg-them:has(.voice-msg) .msg-content-stack {
  max-width: 130px !important;
  align-self: flex-start !important;
}

.msg-them.msg-bubble-wrapper:has(.voice-msg),
.msg-bubble-wrapper.msg-them:has(.voice-msg) {
  max-width: 130px !important;
  justify-content: flex-start !important;
  align-self: flex-start !important;
  margin-right: auto !important;
}

/* ===== 隐藏下载按钮图标 ===== */
.voice-download-btn svg {
    display: none !important;
}
.voice-download-btn {
    opacity: 0 !important;
    pointer-events: auto !important;
    width: 20px !important;
    height: 20px !important;
}

/* ===== 转文字按钮 — 隐形但可点击 ===== */
.voice-transcription-toggle {
    position: absolute !important;
    right: 0 !important;
    top: 0 !important;
    bottom: 0 !important;
    width: 100% !important;
    opacity: 0 !important;
    pointer-events: auto !important;
    z-index: 5 !important;
}
.voice-transcription-toggle svg {
    display: none !important;
}

/* ===== 播放按钮 ===== */
.voice-play-btn {
    width: 28px !important;
    height: 28px !important;
    min-width: 28px !important;
    min-height: 28px !important;
    border-radius: 50% !important;
    border: none !important;
    box-shadow: none !important;
    background: transparent !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    flex-shrink: 0 !important;
    margin-right: 4px !important;
    position: relative !important;
    z-index: 6 !important;
}
.voice-play-btn:active {
    transform: scale(0.92) !important;
    opacity: 0.8 !important;
}
.voice-play-btn svg {
    width: 14px !important;
    height: 14px !important;
}

/* ===== 控件行 ===== */
.voice-controls-row {
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    gap: 4px !important;
    transform: translateY(0px) !important;
    position: relative !important;
}

/* ===== 波形条 — 隐藏 ===== */
.voice-waveform {
    display: none !important;
}

/* ===== 时间戳 ===== */
.voice-duration {
    font-size: 13px !important;
    font-weight: 500 !important;
    flex-shrink: 0 !important;
    position: relative !important;
    z-index: 6 !important;
}

/* ===== 转文字变量 ===== */
:root {
    /* 我方 */
    --voice-me-color: #262626;

    /* 对方 — 白色 */
    --voice-them-color: #ffffff;

    /* 转文字 — 白色独立卡片 */
    --voice-transcription-color: #262626;
    --voice-transcription-bg: #ffffff;
    --voice-transcription-margin-top: 8px;
    --voice-transcription-padding: 10px 14px;
    --voice-transcription-radius: 16px;
    --voice-transcription-border: 1px solid rgba(0,0,0,0.06);
    --voice-transcription-shadow: 0 2px 8px rgba(0,0,0,0.06);

    /* 隐藏下载按钮 */
    --voice-download-display: none;
}

/* ===== 关键：转文字脱离气泡，独立在外 ===== */

/* 1. 语音容器用 flex column，让转文字排在下方 */
.voice-msg,
.voice-msg-me,
.voice-msg-them {
    display: flex !important;
    flex-direction: column !important;
    position: relative !important;
    overflow: visible !important;
}

/* 2. 转文字块 — 绝对定位到语音容器底部外面 */
.voice-transcription {
    position: absolute !important;
    top: 100% !important;              /* 紧贴语音容器底部 */
    left: 0 !important;
    margin-top: 8px !important;
    width: max-content !important;
    max-width: 240px !important;
    white-space: normal !important;
    word-break: break-word !important;
}

/* 我方转文字靠右 */
.voice-msg-me .voice-transcription {
    left: auto !important;
    right: 0 !important;
}

/* 对方转文字靠左 */
.voice-msg-them .voice-transcription {
    left: 0 !important;
    right: auto !important;
}

/* 3. 确保所有父级不裁切转文字 */
.bubble-me-custom:has(.voice-msg),
.bubble-deco-me:has(.voice-msg),
.bubble-them-custom:has(.voice-msg),
.bubble-deco-them:has(.voice-msg),
.msg-me:has(.voice-msg),
.msg-them:has(.voice-msg),
.msg-content-stack:has(.voice-msg),
.msg-bubble-wrapper:has(.voice-msg) {
    overflow: visible !important;
}

/* 4. 语音容器给足够的 padding-bottom 防止被裁 */
.voice-msg,
.voice-msg-me,
.voice-msg-them {
    padding-bottom: 0 !important;      /* 不给 padding，靠 overflow:visible 溢出 */
}
