/* ==========================================
   全局变量 — 素淨模式
   ========================================== */
:root {
  /* 间距 */
  --plain-gap-between-groups: 18px;
  --plain-gap-within-group: 4px;
  --plain-content-max-width: 75%;

  /* 头像 */
  --plain-avatar-size: 36px;
  --plain-avatar-radius: 50%;
  --plain-avatar-gap: 8px;

  /* 全局消息间距 */
  --chat-messages-gap: 0px;
}

/* ==========================================
   气泡 — 素淨模式
   ========================================== */

/* 我方气泡 */
.msg-plain-me {
  background: #ffffff !important;
  color: #262626 !important;
  border: 0.8px solid #c0c0c6 !important;
  padding: 6px 16px !important;
  font-size: 16px !important;
  box-shadow: none !important;
}
.msg-plain-me.plain-single { border-radius: 20px !important; }
.msg-plain-me.plain-first  { border-radius: 20px 20px 4px 20px !important; }
.msg-plain-me.plain-mid    { border-radius: 20px 4px 4px 20px !important; }
.msg-plain-me.plain-last   { border-radius: 20px 4px 20px 20px !important; }

/* 对方气泡 — 黑底白字 */
.msg-plain-them {
  background: #1c1c1e !important;
  color: #ffffff !important;
  border: none !important;
  padding: 6px 16px !important;
  font-size: 16px !important;
  box-shadow: none !important;
