/* ===== 转文字变量 ===== */
:root {
    /* 我方 */
    --voice-me-color: #262626;

    /* 对方 — 白色 */
    --voice-them-color: #ffffff;

    /* 转文字 — 白色独立卡片 */
    --voice-transcription-color: #262626;
    --voice-transcription-bg: #ffffff;
    --voice-transcription-margin-top: 8px;
    --voice-transcription-padding: 10px 14px;
    --voice-transcription-radius: 16px;
    --voice-transcription-border: 1px solid rgba(0,0,0,0.06);
    --voice-transcription-shadow: 0 2px 8px rgba(0,0,0,0.06);

    /* 隐藏下载按钮 */
    --voice-download-display: none;
}

/* ===== 关键：转文字脱离气泡，独立在外 ===== */

/* 1. 语音容器用 flex column，让转文字排在下方 */
.voice-msg,
.voice-msg-me,
.voice-msg-them {
    display: flex !important;
    flex-direction: column !important;
    position: relative !important;
    overflow: visible !important;
}

/* 2. 转文字块 — 绝对定位到语音容器底部外面 */
.voice-transcription {
    position: absolute !important;
    top: 100% !important;              /* 紧贴语音容器底部 */
    left: 0 !important;
    margin-top: 8px !important;
    width: max-content !important;
    max-width: 240px !important;
    white-space: normal !important;
    word-break: break-word !important;
}

/* 我方转文字靠右 */
.voice-msg-me .voice-transcription {
    left: auto !important;
    right: 0 !important;
}

/* 对方转文字靠左 */
.voice-msg-them .voice-transcription {
    left: 0 !important;
    right: auto !important;
}

/* 3. 确保所有父级不裁切转文字 */
.bubble-me-custom:has(.voice-msg),
.bubble-deco-me:has(.voice-msg),
.bubble-them-custom:has(.voice-msg),
.bubble-deco-them:has(.voice-msg),
.msg-me:has(.voice-msg),
.msg-them:has(.voice-msg),
.msg-content-stack:has(.voice-msg),
.msg-bubble-wrapper:has(.voice-msg) {
    overflow: visible !important;
}

/* 4. 语音容器给足够的 padding-bottom 防止被裁 */
.voice-msg,
.voice-msg-me,
.voice-msg-them {
    padding-bottom: 0 !important;      /* 不给 padding，靠 overflow:visible 溢出 */
}
